package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Use platform-independent ping command arguments
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		// Check if ping command failed due to host unreachable vs command error
		if exitErr, ok := err.(*exec.ExitError); ok && exitErr.ExitCode() != 0 {
			// Ping command executed but returned non-zero exit code (host unreachable, etc.)
			return 0, fmt.Errorf("ping failed: %w (output: %s)", err, string(output))
		}
		return 0, fmt.Errorf("failed to execute ping command: %w", err)
	}

	// Look for the line containing RTT statistics
	outputStr := string(output)
	lines := strings.Split(outputStr, "\n")
	var statsLine string
	for _, line := range lines {
		if strings.Contains(line, "rtt min/avg/max") || strings.Contains(line, "round-trip min/avg/max") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	// Extract average latency using more flexible regex
	// Handles different ping output formats:
	// Linux: rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	// macOS: round-trip min/avg/max/stddev = 12.345/23.456/34.567/5.678 ms
	// Also handles integer values without decimal points
	re := regexp.MustCompile(`[\d\.]+/([\d\.]+)/[\d\.]+`)
	matches := re.FindStringSubmatch(statsLine)
	if len(matches) < 2 {
		return 0, errors.New("failed to parse average latency from ping output")
	}

	avgStr := matches[1]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

