	output, err := cmd.CombinedOutput()
	if err != nil {
		// Security fix: Don't include raw command output in error message to avoid information leakage
		// This prevents potential exposure of sensitive system information
		return 0, fmt.Errorf("failed to execute ping: %w", err)
	}

