	// Security fix: Use compiled regex with explicit pattern to prevent regex injection
	re := regexp.MustCompile(`rtt min/avg/max/mdev = (\d+\.\d+)/(\d+\.\d+)/(\d+\.\d+)/(\d+\.\d+) ms`)
	matches := re.FindStringSubmatch(statsLine)
	if len(matches) < 3 { // Need at least full match + avg value
