package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
	"time"
)

// MeasureLatency pings a specified host a defined number of times and returns the average latency in milliseconds.
// It uses the system's ping command via os/exec.
func MeasureLatency(host string, count int) (float64, error) {
	// Validate inputs
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}
	if count <= 0 {
		return 0, fmt.Errorf("count must be positive")
	}

	// Determine ping command based on OS
	var cmdArgs []string
	switch os := getOS(); os {
	case "windows":
		cmdArgs = []string{"-n", strconv.Itoa(count), "-w", "1000", host}
	case "darwin", "linux":
		cmdArgs = []string{"-c", strconv.Itoa(count), "-W", "1", host}
	default:
		// Try Linux-style as default
		cmdArgs = []string{"-c", strconv.Itoa(count), "-W", "1", host}
	}

	// Execute ping command
	cmd := exec.Command("ping", cmdArgs...)
	var stdout, stderr bytes.Buffer
	cmd.Stdout = &stdout
	cmd.Stderr = &stderr

	// Set timeout for the ping command
	timeout := time.Duration(count+2) * time.Second
	cmdTimer := time.AfterFunc(timeout, func() {
		if cmd.Process != nil {
			cmd.Process.Kill()
		}
	})
	defer cmdTimer.Stop()

	err := cmd.Run()
	if err != nil {
		return 0, fmt.Errorf("ping failed: %v\nstderr: %s", err, stderr.String())
	}

	// Parse output to extract round-trip times
	output := stdout.String()
	latencies, err := parsePingOutput(output)
	if err != nil {
		return 0, fmt.Errorf("failed to parse ping output: %v", err)
	}

	if len(latencies) == 0 {
		return 0, fmt.Errorf("no valid latency measurements found")
	}

	// Calculate average
	var sum float64
	for _, lat := range latencies {
		sum += lat
	}
	return sum / float64(len(latencies)), nil
}

// getOS returns the current operating system identifier
func getOS() string {
	return strings.ToLower(runtime.GOOS)
}

// parsePingOutput extracts latency values from ping command output
func parsePingOutput(output string) ([]float64, error) {
	var latencies []float64
	lines := strings.Split(output, "\n")

	// Regular expressions for different ping output formats
	patterns := []*regexp.Regexp{
		// Windows format: "Reply from 8.8.8.8: bytes=32 time=12ms TTL=116"
		regexp.MustCompile(`time[=<>](\d+(?:\.\d+)?)\s*ms`),
		// Linux/macOS format: "64 bytes from 8.8.8.8: icmp_seq=0 ttl=116 time=12.345 ms"
		regexp.MustCompile(`time=(\d+(?:\.\d+)?)\s*ms`),
		// Alternative format: "rtt min/avg/max/mdev = 12.345/23.456/34.567/4.321 ms"
		regexp.MustCompile(`(\d+(?:\.\d+)?)/(\d+(?:\.\d+)?)/(\d+(?:\.\d+)?)/(\d+(?:\.\d+)?)\s*ms`),
	}

	for _, line := range lines {
		line = strings.TrimSpace(line)
		if line == "" {
			continue
		}

		// Try each pattern
		for _, pattern := range patterns {
			matches := pattern.FindStringSubmatch(line)
			if matches == nil {
				continue
			}

			// Handle rtt min/avg/max/mdev format (use avg value)
			if len(matches) > 2 && strings.Contains(line, "rtt") {
