// It uses the system's ping command via os/exec package.
func MeasureLatency(host string, count int) (float64, error) {
	// Validate input parameters
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}
	if count <= 0 {
		return 0, fmt.Errorf("count must be greater than 0")
	}

	// Determine OS-specific ping command arguments
	var cmd *exec.Cmd
	switch runtime.GOOS {
	case "windows":
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	case "darwin", "freebsd":
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	case "linux":
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), "-W", "5", host)
	default:
		// Fallback for other Unix-like systems
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// Execute the ping command and capture output
	var stdout, stderr bytes.Buffer
	cmd.Stdout = &stdout
	cmd.Stderr = &stderr

	if err := cmd.Run(); err != nil {
		return 0, fmt.Errorf("ping command failed: %v, stderr: %s", err, stderr.String())
	}

	// Parse output to extract latency values
	output := stdout.String()
	var totalLatency float64
	var successfulPings int

	lines := strings.Split(output, "\n")
	for _, line := range lines {
		line = strings.ToLower(line)

		// Different OSes have different output formats
		if strings.Contains(line, "time=") || strings.Contains(line, "time<") {
			// Linux/macOS format: "64 bytes from 8.8.8.8: icmp_seq=0 ttl=115 time=12.3 ms"
			// Windows format: "Reply from 8.8.8.8: bytes=32 time=12ms TTL=115"
			timeIndex := strings.Index(line, "time=")
			if timeIndex == -1 {
				timeIndex = strings.Index(line, "time<")
				if timeIndex == -1 {
					continue
				}
			}

			// Extract the time value
			timePart := line[timeIndex+5:]
			endIndex := strings.IndexAny(timePart, "ms ")
			if endIndex == -1 {
				continue
			}

			timeStr := strings.TrimSpace(timePart[:endIndex])
			latency, err := strconv.ParseFloat(timeStr, 64)
			if err != nil {
				continue
			}

			totalLatency += latency
			successfulPings++
		} else if strings.Contains(line, "avg =") || strings.Contains(line, "average =") {
			// Windows summary format: "Average = 12ms"
			// Extract average directly from summary line
			avgIndex := strings.Index(line, "avg =")
			if avgIndex == -1 {
				avgIndex = strings.Index(line, "average =")
				if avgIndex == -1 {
					continue
				}
				avgIndex += 9 // "average =".length
			} else {
				avgIndex += 5 // "avg =".length
			}

			avgPart := strings.TrimSpace(line[avgIndex:])
			endIndex := strings.IndexAny(avgPart, "ms")
			if endIndex == -1 {
				continue
			}

			avgStr := strings.TrimSpace(avgPart[:endIndex])
			avg, err := strconv.ParseFloat(avgStr, 64)
			if err != nil {
				continue
			}

			// If we found the average in summary, return it directly
			return avg, nil
		}
	}

	// Calculate average from individual ping times
	if successfulPings == 0 {
		return 0, fmt.Errorf("no successful ping responses received")
	}

	return totalLatency / float64(successfulPings), nil
}

func main() {
	// Example usage
	host := "8.8.8.8"
	count := 4

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average latency to %s over %d pings: %.2f ms\n", host, count, avgLatency)
}

