func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Build ping command based on OS
	var cmd *exec.Cmd
	switch runtime.GOOS {
	case "windows":
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	default: // Linux, macOS, BSD, etc.
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		// Ignore exit status errors as ping may succeed but return non-zero on packet loss
		if _, ok := err.(*exec.ExitError); !ok {
			return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, string(output))
		}
	}

	outputStr := string(output)
	lines := strings.Split(outputStr, "\n")

	// Find the line containing RTT statistics
	var statsLine string
	for _, line := range lines {
		if strings.Contains(line, "rtt min/avg/max") || 
		   strings.Contains(line, "round-trip min/avg/max") ||
		   strings.Contains(line, "Average =") { // Windows format
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	// Parse average latency based on OS-specific output format
	var avgStr string
	switch runtime.GOOS {
	case "windows":
		// Windows format: "Average = 23ms"
		parts := strings.Split(statsLine, "Average =")
		if len(parts) != 2 {
			return 0, errors.New("failed to parse Windows ping output")
		}
		avgStr = strings.TrimSpace(strings.TrimSuffix(parts[1], "ms"))
	default:
		// Unix format: "rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms"
		parts := strings.Split(statsLine, "=")
		if len(parts) != 2 {
			return 0, errors.New("failed to parse Unix ping output")
		}
		numbers := strings.TrimSpace(parts[1])
		// Split by '/' to get min/avg/max/mdev values
		numberParts := strings.Split(numbers, "/")
		if len(numberParts) < 2 {
			return 0, errors.New("invalid RTT statistics format")
		}
		// Extract average (second value) and remove unit if present
		avgStr = strings.Fields(numberParts[1])[0]
	}

	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

