// MeasureLatency pings the specified host a given number of times and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	// Validate inputs
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}
	if count <= 0 {
		return 0, fmt.Errorf("count must be positive")
	}

	// Determine ping command based on operating system
	var cmd *exec.Cmd
	switch runtime.GOOS {
	case "windows":
