	default: // Unix-like systems
		avgLatency, parseErr = parseUnixPing(stdout.String())
	}

	if parseErr != nil {
		return 0, fmt.Errorf("failed to parse ping output: %v", parseErr)
	}

	return avgLatency, nil
}

// parseWindowsPing extracts average latency from Windows ping output
func parseWindowsPing(output string) (float64, error) {
	lines := strings.Split(output, "\n")
	for i := len(lines) - 1; i >= 0; i-- {
		line := strings.ToLower(strings.TrimSpace(lines[i]))
		if strings.Contains(line, "average =") {
			// Example: "Average = 15ms"
			parts := strings.Split(line, "=")
			if len(parts) != 2 {
				continue
			}
			timeStr := strings.TrimSpace(parts[1])
			// Remove "ms" suffix if present
			timeStr = strings.TrimSuffix(timeStr, "ms")
			timeStr = strings.TrimSpace(timeStr)

			latency, err := strconv.ParseFloat(timeStr, 64)
			if err != nil {
				return 0, fmt.Errorf("invalid latency format: %s", timeStr)
			}
			return latency, nil
		}
	}
	return 0, fmt.Errorf("average latency not found in ping output")
}

// parseUnixPing extracts average latency from Unix-like ping output
func parseUnixPing(output string) (float64, error) {
	lines := strings.Split(output, "\n")
	for _, line := range lines {
		line = strings.TrimSpace(line)
		if strings.Contains(line, "rtt min/avg/max/mdev") || 
		   strings.Contains(line, "round-trip min/avg/max/stddev") {
			// Examples:
			// "rtt min/avg/max/mdev = 10.123/20.456/30.789/5.678 ms"
			// "round-trip min/avg/max/stddev = 10.123/20.456/30.789/5.678 ms"
			parts := strings.Split(line, "=")
			if len(parts) != 2 {
				continue
			}
			stats := strings.TrimSpace(parts[1])
			// Remove "ms" suffix if present
			stats = strings.TrimSuffix(stats, "ms")
			stats = strings.TrimSpace(stats)

			// Split by "/" to get individual values
			values := strings.Split(stats, "/")
			if len(values) < 2 {
				return 0, fmt.Errorf("invalid rtt format: %s", stats)
			}

			// The second value is the average
			avgStr := strings.TrimSpace(values[1])
			latency, err := strconv.ParseFloat(avgStr, 64)
			if err != nil {
				return 0, fmt.Errorf("invalid average latency format: %s", avgStr)
			}
			return latency, nil
		}
	}
	return 0, fmt.Errorf("rtt statistics not found in ping output")
}

func main() {
	// Example usage with command line arguments
	if len(os.Args) < 3 {
		fmt.Println("Usage: go run main.go <host> <count>")
		fmt.Println("Example: go run main.go google.com 4")
		os.Exit(1)
	}

