		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	default:
		return 0, fmt.Errorf("unsupported operating system: %s", runtime.GOOS)
	}

	// Capture the command output
	var out bytes.Buffer
	cmd.Stdout = &out
	cmd.Stderr = &out

	// Execute the ping command
	err := cmd.Run()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w\nOutput: %s", err, out.String())
	}

	// Parse the output to extract round-trip times
	outputStr := out.String()
	var totalLatency float64
	var successfulPings int

	lines := strings.Split(outputStr, "\n")
	for _, line := range lines {
		line = strings.ToLower(line)

		// Different parsing for Windows vs Unix-like systems
		if runtime.GOOS == "windows" {
			// Windows format: "Reply from 192.168.1.1: bytes=32 time=1ms TTL=64"
			if strings.Contains(line, "time=") && strings.Contains(line, "ttl=") {
				timeIndex := strings.Index(line, "time=")
				if timeIndex != -1 {
					timePart := line[timeIndex+5:]
					msIndex := strings.Index(timePart, "ms")
					if msIndex != -1 {
						timeStr := strings.TrimSpace(timePart[:msIndex])
						if time, err := strconv.ParseFloat(timeStr, 64); err == nil {
							totalLatency += time
							successfulPings++
						}
					}
				}
			}
		} else {
			// Unix-like format: "64 bytes from 8.8.8.8: icmp_seq=1 ttl=117 time=12.3 ms"
			if strings.Contains(line, "time=") {
				timeIndex := strings.Index(line, "time=")
				if timeIndex != -1 {
					timePart := line[timeIndex+5:]
					// Find the end of the time value (space or newline)
					endIndex := strings.IndexAny(timePart, " \n")
					if endIndex != -1 {
						timeStr := strings.TrimSpace(timePart[:endIndex])
						if time, err := strconv.ParseFloat(timeStr, 64); err == nil {
							totalLatency += time
							successfulPings++
						}
					}
				}
			}
		}
	}

	if successfulPings == 0 {
		return 0, fmt.Errorf("no successful pings received. Output:\n%s", outputStr)
	}

	return totalLatency / float64(successfulPings), nil
}

func main() {
	// Example usage with command-line arguments
	if len(os.Args) < 3 {
		fmt.Println("Usage: go run main.go <host> <count>")
		fmt.Println("Example: go run main.go 8.8.8.8 4")
		os.Exit(1)
	}

	host := os.Args[1]
	count, err := strconv.Atoi(os.Args[2])
	if err != nil {
		fmt.Printf("Invalid count: %v\n", err)
		os.Exit(1)
	}

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s: %.2f ms (based on %d pings)\n", host, avgLatency, count)
}

