// MeasureLatency pings a specified host a given number of times and returns the average latency in milliseconds.
// It uses the system's ping command via os/exec package.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be positive, got %d", count)
	}

	// Build ping command based on operating system
	var cmd *exec.Cmd
	switch runtime.GOOS {
	case "windows":
		cmd = exec.Command("ping", host, "-n", strconv.Itoa(count))
	case "darwin", "linux", "freebsd", "netbsd", "openbsd":
		cmd = exec.Command("ping", host, "-c", strconv.Itoa(count))
	default:
		return 0, fmt.Errorf("unsupported operating system: %s", runtime.GOOS)
	}

	// Set timeout to prevent hanging (10 seconds per ping attempt)
	timeout := time.Duration(count*10) * time.Second
	cmd.Stdout = &bytes.Buffer{}
	cmd.Stderr = &bytes.Buffer{}

	// Execute the command with timeout
	err := cmd.Start()
	if err != nil {
		return 0, fmt.Errorf("failed to start ping command: %w", err)
	}

	timer := time.AfterFunc(timeout, func() {
		cmd.Process.Kill()
	})
	defer timer.Stop()

	err = cmd.Wait()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w. Stderr: %s", err, cmd.Stderr.(*bytes.Buffer).String())
	}

	// Parse output based on operating system
	output := cmd.Stdout.(*bytes.Buffer).String()
	avgLatency, err := parsePingOutput(output, runtime.GOOS)
	if err != nil {
		return 0, fmt.Errorf("failed to parse ping output: %w", err)
	}

	return avgLatency, nil
}

// parsePingOutput extracts average latency from ping command output
func parsePingOutput(output string, os string) (float64, error) {
	lines := strings.Split(output, "\n")

	switch os {
	case "windows":
		// Windows ping output format: "Average = 25ms"
		for _, line := range lines {
			if strings.Contains(line, "Average =") {
				parts := strings.Split(line, "=")
				if len(parts) != 2 {
					continue
				}
				timeStr := strings.TrimSpace(parts[1])
				// Remove "ms" suffix
				timeStr = strings.TrimSuffix(timeStr, "ms")
				latency, err := strconv.ParseFloat(timeStr, 64)
				if err != nil {
					return 0, fmt.Errorf("failed to parse latency value: %w", err)
				}
				return latency, nil
			}
		}

	default:
		// Unix-like systems (Linux, macOS, BSD) output format: "rtt min/avg/max/mdev = 1.234/5.678/9.012/3.456 ms"
		for _, line := range lines {
			if strings.Contains(line, "rtt min/avg/max/mdev") || 
			   strings.Contains(line, "round-trip min/avg/max/stddev") {
				parts := strings.Split(line, "=")
				if len(parts) != 2 {
					continue
				}
				stats := strings.TrimSpace(parts[1])
				// Split by "/" to get min/avg/max/mdev values
				values := strings.Split(stats, "/")
				if len(values) < 2 {
					continue
				}
				// The second value is average
				avgStr := strings.TrimSpace(values[1])
				// Remove unit suffix if present
				avgStr = strings.TrimSuffix(avgStr, " ms")
				latency, err := strconv.ParseFloat(avgStr, 64)
				if err != nil {
					return 0, fmt.Errorf("failed to parse latency value: %w", err)
				}
				return latency, nil
			}
		}
	}

	return 0, fmt.Errorf("could not find average latency in ping output")
}

// Example main function demonstrating usage
func main() {
	// Example usage
	host := "google.com"
	count := 4

	fmt.Printf("Measuring latency to %s with %d pings...\n", host, count)

