// MeasureLatency pings the specified host a given number of times and returns
// the average latency in milliseconds. It uses the system's ping command via
// os/exec. Supports Linux, macOS, and Windows.
func MeasureLatency(host string, count int) (float64, error) {
	// Validate inputs
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}
	if count <= 0 {
		return 0, fmt.Errorf("count must be positive")
	}

	// Build ping command based on OS
	var cmd *exec.Cmd
	switch runtime.GOOS {
	case "windows":
		cmd = exec.Command("ping", host, "-n", strconv.Itoa(count))
	case "darwin", "linux", "freebsd", "netbsd", "openbsd":
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	default:
		return 0, fmt.Errorf("unsupported operating system: %s", runtime.GOOS)
	}

	// Execute command and capture output
	var out bytes.Buffer
	var stderr bytes.Buffer
	cmd.Stdout = &out
	cmd.Stderr = &stderr

	if err := cmd.Run(); err != nil {
		return 0, fmt.Errorf("ping failed: %v\nstderr: %s", err, stderr.String())
	}

	// Parse output based on OS
	var avgLatency float64
	var parseErr error
	switch runtime.GOOS {
	case "windows":
		avgLatency, parseErr = parseWindowsOutput(out.String())
	default: // Unix-like systems
		avgLatency, parseErr = parseUnixOutput(out.String())
	}

	if parseErr != nil {
		return 0, fmt.Errorf("failed to parse ping output: %v", parseErr)
	}

	return avgLatency, nil
}

// parseUnixOutput extracts average latency from Linux/macOS ping output
func parseUnixOutput(output string) (float64, error) {
	lines := strings.Split(output, "\n")
	for i := len(lines) - 1; i >= 0; i-- {
		line := strings.TrimSpace(lines[i])
		if strings.Contains(line, "rtt min/avg/max/mdev") || strings.Contains(line, "round-trip min/avg/max/stddev") {
			// Example: "rtt min/avg/max/mdev = 12.345/45.678/78.901/12.345 ms"
			parts := strings.Split(line, "=")
			if len(parts) != 2 {
				continue
			}
			stats := strings.TrimSpace(parts[1])
			// Split by "/" and take the second value (average)
			values := strings.Split(stats, "/")
			if len(values) < 2 {
				return 0, fmt.Errorf("malformed stats line: %s", line)
			}
			avgStr := strings.Fields(values[1])[0] // Remove unit if present
			avg, err := strconv.ParseFloat(avgStr, 64)
			if err != nil {
				return 0, fmt.Errorf("failed to parse latency value: %v", err)
			}
			return avg, nil
		}
	}
	return 0, fmt.Errorf("average latency not found in output")
}

// parseWindowsOutput extracts average latency from Windows ping output
func parseWindowsOutput(output string) (float64, error) {
	lines := strings.Split(output, "\n")
	for i := len(lines) - 1; i >= 0; i-- {
		line := strings.TrimSpace(lines[i])
		if strings.Contains(line, "Average =") {
			// Example: "Average = 45ms"
			parts := strings.Split(line, "=")
			if len(parts) != 2 {
				continue
			}
			valueStr := strings.TrimSpace(parts[1])
			// Remove "ms" suffix if present
			valueStr = strings.TrimSuffix(valueStr, "ms")
			valueStr = strings.TrimSpace(valueStr)
			avg, err := strconv.ParseFloat(valueStr, 64)
			if err != nil {
				return 0, fmt.Errorf("failed to parse latency value: %v", err)
			}
			return avg, nil
		}
	}
	return 0, fmt.Errorf("average latency not found in output")
}

// Example main function demonstrating usage
func main() {
	// Example: ping google.com 4 times
	host := "google.com"
	count := 4

	latency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	fmt.Printf("Average latency to %s (%d pings): %.2f ms\n", host, count, latency)
}

