import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Determine the appropriate ping command based on the operating system
	var cmd *exec.Cmd
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		// Unix-like systems (Linux, macOS, etc.)
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		// Check if the error is due to non-zero exit code (common for ping)
		// Ping often returns non-zero when there's packet loss, but we may still get output
		if len(output) == 0 {
			return 0, fmt.Errorf("failed to execute ping: %w", err)
		}
		// Continue to parse output even if there's an error
	}

	// Look for the line containing RTT statistics
	outputStr := string(output)
	lines := strings.Split(outputStr, "\n")
	var statsLine string
	for _, line := range lines {
		// Match common ping output patterns for different OSes
		if strings.Contains(line, "rtt") || strings.Contains(line, "round-trip") || 
		   strings.Contains(line, "Average") || strings.Contains(line, "avg") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	// Extract average latency using regex patterns for different ping formats
	var avgStr string

	// Pattern 1: Linux format "rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms"
	re1 := regexp.MustCompile(`rtt.*min/avg/max.*=.*\d+\.\d+/([\d.]+)/\d+\.\d+/\d+\.\d+\s*ms`)
	// Pattern 2: macOS format "round-trip min/avg/max/stddev = 12.345/23.456/34.567/5.678 ms"
	re2 := regexp.MustCompile(`round-trip.*min/avg/max.*=.*\d+\.\d+/([\d.]+)/\d+\.\d+/\d+\.\d+\s*ms`)
	// Pattern 3: Windows format "Average = 23ms"
	re3 := regexp.MustCompile(`Average\s*=\s*(\d+)(?:\.\d+)?\s*ms`)
	// Pattern 4: Alternative Windows format "Average = 23ms"
	re4 := regexp.MustCompile(`Average\s*=\s*(\d+)(?:\.\d+)?ms`)
	// Pattern 5: Simple avg pattern (fallback)
	re5 := regexp.MustCompile(`avg\s*[=:]\s*(\d+)(?:\.\d+)?\s*ms`)

	// Try patterns in order
	switch {
	case re1.MatchString(statsLine):
		matches := re1.FindStringSubmatch(statsLine)
		if len(matches) >= 2 {
			avgStr = matches[1]
		}
	case re2.MatchString(statsLine):
		matches := re2.FindStringSubmatch(statsLine)
		if len(matches) >= 2 {
			avgStr = matches[1]
		}
	case re3.MatchString(statsLine):
		matches := re3.FindStringSubmatch(statsLine)
		if len(matches) >= 2 {
			avgStr = matches[1]
		}
	case re4.MatchString(statsLine):
		matches := re4.FindStringSubmatch(statsLine)
		if len(matches) >= 2 {
			avgStr = matches[1]
		}
	case re5.MatchString(statsLine):
		matches := re5.FindStringSubmatch(statsLine)
		if len(matches) >= 2 {
			avgStr = matches[1]
		}
	}

	if avgStr == "" {
		return 0, errors.New("failed to parse average latency from ping output")
	}

	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

