package main

import (
	"bytes"
	"fmt"
	"os/exec"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host a given number of times and returns
// the average latency in milliseconds. It uses the system's ping command
// via os/exec.
func MeasureLatency(host string, count int) (float64, error) {
	// Validate input parameters
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}
	if count <= 0 {
		return 0, fmt.Errorf("count must be positive")
	}

	// Determine the appropriate ping command based on OS
	var cmd *exec.Cmd
	switch runtime.GOOS {
	case "windows":
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	case "darwin", "linux", "freebsd", "netbsd", "openbsd":
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	default:
		return 0, fmt.Errorf("unsupported operating system: %s", runtime.GOOS)
	}

	// Execute the ping command and capture output
	var out bytes.Buffer
	cmd.Stdout = &out
	cmd.Stderr = &out
	if err := cmd.Run(); err != nil {
		return 0, fmt.Errorf("ping command failed: %w\noutput: %s", err, out.String())
	}

	// Parse the output to extract latency values
	latencies, err := parsePingOutput(out.String(), runtime.GOOS)
	if err != nil {
		return 0, fmt.Errorf("failed to parse ping output: %w", err)
	}

	// Calculate average latency
	if len(latencies) == 0 {
		return 0, fmt.Errorf("no latency data found in ping output")
	}

	var sum float64
	for _, latency := range latencies {
		sum += latency
	}
	return sum / float64(len(latencies)), nil
}

// parsePingOutput extracts latency values (in milliseconds) from ping command output.
func parsePingOutput(output string, os string) ([]float64, error) {
	lines := strings.Split(output, "\n")
	var latencies []float64

	for _, line := range lines {
		line = strings.TrimSpace(line)
		if line == "" {
			continue
		}

		// Look for lines containing time= or time< (common in ping outputs)
		if strings.Contains(line, "time=") || strings.Contains(line, "time<") {
			latency, err := extractLatencyFromLine(line, os)
			if err == nil {
				latencies = append(latencies, latency)
			}
		}
	}

	return latencies, nil
}

// extractLatencyFromLine extracts the latency value from a single ping output line.
func extractLatencyFromLine(line, os string) (float64, error) {
	// Common patterns for latency in ping output
	var timeStr string

	if os == "windows" {
		// Windows format: "Reply from 192.168.1.1: bytes=32 time=1ms TTL=64"
		timePrefix := "time="
		if idx := strings.Index(line, timePrefix); idx != -1 {
			timePart := line[idx+len(timePrefix):]
			// Extract until non-digit or decimal point
			var timeChars []byte
			for _, ch := range timePart {
				if (ch >= '0' && ch <= '9') || ch == '.' {
					timeChars = append(timeChars, byte(ch))
				} else {
					break
				}
			}
			timeStr = string(timeChars)
		}
	} else {
		// Unix-like format: "64 bytes from 8.8.8.8: icmp_seq=0 ttl=117 time=11.7 ms"
		timePrefix := "time="
		if idx := strings.Index(line, timePrefix); idx != -1 {
			timePart := line[idx+len(timePrefix):]
			// Extract until " ms"
			if endIdx := strings.Index(timePart, " ms"); endIdx != -1 {
				timeStr = timePart[:endIdx]
			}
		}
	}

	if timeStr == "" {
		return 0, fmt.Errorf("no latency value found in line: %s", line)
	}

	// Convert to float64
	latency, err := strconv.ParseFloat(timeStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to parse latency value '%s': %w", timeStr, err)
	}

	return latency, nil
}

func main() {
	// Example usage
	host := "8.8.8.8"
	count := 4

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average latency to %s over %d pings: %.2f ms\n", host, count, avgLatency)
}

