package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
	"runtime"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
// Supports Linux (ping -c), macOS (ping -c), and Windows (ping -n).
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Build ping command based on OS
	var cmd *exec.Cmd
	switch runtime.GOOS {
	case "windows":
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	default: // Linux, macOS, BSD, etc.
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		// ping returns exit code 1 on most systems when packets are lost,
		// but we still want to parse output if we have statistics
		if len(output) == 0 {
			return 0, fmt.Errorf("failed to execute ping: %w", err)
		}
		// Continue parsing even if there's an error (like packet loss)
	}

	outputStr := string(output)

	// Try different regex patterns for various ping output formats
	patterns := []*regexp.Regexp{
		// Linux: rtt min/avg/max/mdev = 1.234/5.678/9.012/3.456 ms
		regexp.MustCompile(`rtt min/avg/max/mdev = [\d.]+/([\d.]+)/[\d.]+/[\d.]+ ms`),
		// macOS: round-trip min/avg/max/stddev = 1.234/5.678/9.012/3.456 ms
		regexp.MustCompile(`round-trip min/avg/max/stddev = [\d.]+/([\d.]+)/[\d.]+/[\d.]+ ms`),
		// Windows: Minimum = 1ms, Maximum = 9ms, Average = 5ms
		regexp.MustCompile(`Average = ([\d]+)ms`),
		// Alternative Windows format: Average = 5ms
		regexp.MustCompile(`Average = ([\d.]+)ms`),
		// Some systems: avg = 5.678 ms
		regexp.MustCompile(`avg = ([\d.]+) ms`),
	}

	var avgStr string
	for _, pattern := range patterns {
		matches := pattern.FindStringSubmatch(outputStr)
		if matches != nil && len(matches) >= 2 {
			avgStr = matches[1]
			break
		}
	}

	if avgStr == "" {
		// Fallback: look for any line containing "avg" and extract numbers
		lines := strings.Split(outputStr, "\n")
		for _, line := range lines {
			if strings.Contains(strings.ToLower(line), "avg") {
				// Extract first decimal number from the line
				fallbackRe := regexp.MustCompile(`[\d.]+`)
				numbers := fallbackRe.FindAllString(line, -1)
				if len(numbers) > 0 {
					// Try to use the largest number (likely the average)
					for _, num := range numbers {
						if strings.Contains(num, ".") || len(num) > 2 {
							avgStr = num
							break
						}
					}
					if avgStr != "" {
						break
					}
				}
			}
		}
	}

	if avgStr == "" {
		return 0, errors.New("could not find average latency in ping output")
	}

	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency '%s' to float: %w", avgStr, err)
	}

	return avg, nil
}

