package main

import (
	"bytes"
	"fmt"
	"os/exec"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host a given number of times and returns the average latency in milliseconds.
// It uses the system's ping command via os/exec.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be positive, got %d", count)
	}

	// Build ping command based on OS
	var cmd *exec.Cmd
	switch runtime.GOOS {
	case "windows":
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	case "darwin", "linux", "freebsd", "netbsd", "openbsd":
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	default:
		return 0, fmt.Errorf("unsupported operating system: %s", runtime.GOOS)
	}

	// Execute command and capture output
	var out bytes.Buffer
	cmd.Stdout = &out
	err := cmd.Run()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %v", err)
	}

	// Parse output based on OS
	output := out.String()

	if runtime.GOOS == "windows" {
		// Windows ping output format: "Minimum = 0ms, Maximum = 10ms, Average = 5ms"
		lines := strings.Split(output, "\n")
		for _, line := range lines {
			if strings.Contains(line, "Average =") {
				parts := strings.Split(line, "Average =")
				if len(parts) < 2 {
					continue
				}
				timeStr := strings.TrimSpace(strings.Split(parts[1], "ms")[0])
				avgTime, err := strconv.ParseFloat(timeStr, 64)
				if err != nil {
					return 0, fmt.Errorf("failed to parse average time: %v", err)
				}
				return avgTime, nil
			}
		}
	} else {
		// Unix-like ping output format: "rtt min/avg/max/mdev = 1.234/5.678/9.012/3.456 ms"
		lines := strings.Split(output, "\n")
		for _, line := range lines {
			if strings.Contains(line, "rtt") || strings.Contains(line, "round-trip") {
				parts := strings.Split(line, "=")
				if len(parts) < 2 {
					continue
				}
				stats := strings.Fields(strings.TrimSpace(parts[1]))[0]
				values := strings.Split(stats, "/")
				if len(values) < 2 {
					return 0, fmt.Errorf("unexpected ping output format: %s", line)
				}
				avgTime, err := strconv.ParseFloat(values[1], 64)
				if err != nil {
					return 0, fmt.Errorf("failed to parse average time: %v", err)
				}
				return avgTime, nil
			}
		}
	}

	return 0, fmt.Errorf("could not find latency information in ping output")
}

func main() {
	// Example usage
	host := "google.com"
	count := 4

	latency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	fmt.Printf("Average latency to %s (%d pings): %.2f ms\n", host, count, latency)
}

