func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be positive, got %d", count)
	}
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	// Determine OS-specific ping command
	var cmd *exec.Cmd
	switch {
	case isWindows():
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	case isDarwin():
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	default: // Linux and other Unix-like systems
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// Set timeout to prevent hanging
	timeout := time.Duration(count*2+5) * time.Second
	cmd.WaitDelay = timeout

	var stdout, stderr bytes.Buffer
	cmd.Stdout = &stdout
	cmd.Stderr = &stderr

	if err := cmd.Run(); err != nil {
		return 0, fmt.Errorf("ping failed: %v\nstderr: %s", err, stderr.String())
	}

	// Parse ping output based on OS
	var totalLatency float64
	var successfulPings int

	scanner := bufio.NewScanner(&stdout)
	for scanner.Scan() {
		line := scanner.Text()
		latency, ok := parsePingLine(line)
		if ok {
			totalLatency += latency
			successfulPings++
		}
	}

	if err := scanner.Err(); err != nil {
		return 0, fmt.Errorf("error reading ping output: %v", err)
	}

	if successfulPings == 0 {
		return 0, fmt.Errorf("no successful ping responses received")
	}

	return totalLatency / float64(successfulPings), nil
}

// parsePingLine extracts latency from a ping output line
func parsePingLine(line string) (float64, bool) {
	line = strings.ToLower(line)

	// Patterns for different ping output formats
	patterns := []*regexp.Regexp{
		// Windows: "Reply from 192.168.1.1: bytes=32 time=12ms TTL=64"
		regexp.MustCompile(`time[=:](\d+(?:\.\d+)?)\s*ms`),
