package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
// This function works on Linux, macOS, and Windows systems.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Build ping command based on OS
	var cmd *exec.Cmd
	switch runtime.GOOS {
	case "windows":
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	case "darwin":
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	default: // Linux and other Unix-like systems
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		// Check if we got partial output that might contain statistics
		// Some ping implementations return error on packet loss but still output stats
		if len(output) == 0 {
			return 0, fmt.Errorf("failed to execute ping: %w", err)
		}
		// Continue parsing even with error, as statistics might be available
	}

	outputStr := string(output)

	// Parse output based on OS
	var avgStr string
	switch runtime.GOOS {
	case "windows":
		avgStr, err = parseWindowsPingOutput(outputStr)
	default: // Unix-like systems (Linux, macOS)
		avgStr, err = parseUnixPingOutput(outputStr)
	}

	if err != nil {
		return 0, fmt.Errorf("failed to parse ping output: %w (output: %s)", err, outputStr)
	}

	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

// parseUnixPingOutput parses ping output from Linux/macOS systems
func parseUnixPingOutput(outputStr string) (string, error) {
	lines := strings.Split(outputStr, "\n")
	var statsLine string

	// Look for RTT statistics line - different formats for different systems
	for _, line := range lines {
		if strings.Contains(line, "rtt min/avg/max") || 
		   strings.Contains(line, "round-trip min/avg/max") ||
		   strings.Contains(line, "min/avg/max") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		return "", errors.New("could not find RTT statistics in ping output")
	}

	// Regex patterns for different ping output formats
	patterns := []*regexp.Regexp{
		// Linux format: rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
		regexp.MustCompile(`rtt min/avg/max/mdev = [\d.]+/([\d.]+)/[\d.]+/[\d.]+`),
		// macOS format: round-trip min/avg/max/stddev = 12.345/23.456/34.567/5.678 ms
		regexp.MustCompile(`round-trip min/avg/max/stddev = [\d.]+/([\d.]+)/[\d.]+/[\d.]+`),
		// Some systems: min/avg/max = 12.345/23.456/34.567 ms
		regexp.MustCompile(`min/avg/max = [\d.]+/([\d.]+)/[\d.]+`),
	}

	for _, re := range patterns {
		matches := re.FindStringSubmatch(statsLine)
		if len(matches) >= 2 {
			return matches[1], nil
		}
	}

	return "", errors.New("failed to parse average latency from ping output")
}

// parseWindowsPingOutput parses ping output from Windows systems
func parseWindowsPingOutput(outputStr string) (string, error) {
	lines := strings.Split(outputStr, "\n")

	// Look for the line containing average statistics
	for i := len(lines) - 1; i >= 0; i-- {
		line := strings.TrimSpace(lines[i])
		if strings.Contains(line, "Average =") {
			// Extract the average value
			re := regexp.MustCompile(`Average = (\d+)ms`)
			matches := re.FindStringSubmatch(line)
			if len(matches) >= 2 {
				return matches[1], nil
			}
		}
	}

	return "", errors.New("could not find average latency in Windows ping output")
}

