import (
	"bytes"
	"fmt"
	"os/exec"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings a specified host a given number of times
// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	// Validate input parameters
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}
	if count <= 0 {
		return 0, fmt.Errorf("count must be positive")
	}

	// Determine ping command based on operating system
	var cmd *exec.Cmd
	switch runtime.GOOS {
	case "windows":
		cmd = exec.Command("ping", host, "-n", strconv.Itoa(count))
	case "darwin", "linux", "freebsd", "netbsd", "openbsd":
		cmd = exec.Command("ping", host, "-c", strconv.Itoa(count))
	default:
		return 0, fmt.Errorf("unsupported operating system: %s", runtime.GOOS)
	}

	// Execute ping command and capture output
	var out bytes.Buffer
	cmd.Stdout = &out
	if err := cmd.Run(); err != nil {
		return 0, fmt.Errorf("ping command failed: %w", err)
	}

	// Parse output to extract latency values
	latencies, err := parsePingOutput(out.String(), runtime.GOOS)
	if err != nil {
		return 0, fmt.Errorf("failed to parse ping output: %w", err)
	}

	// Calculate average latency
	if len(latencies) == 0 {
		return 0, fmt.Errorf("no valid latency measurements found")
	}

	var sum float64
	for _, latency := range latencies {
		sum += latency
	}
	return sum / float64(len(latencies)), nil
}

// parsePingOutput extracts latency values from ping command output
func parsePingOutput(output string, os string) ([]float64, error) {
	lines := strings.Split(output, "\n")
	var latencies []float64

	for _, line := range lines {
		line = strings.ToLower(strings.TrimSpace(line))
		if line == "" {
			continue
		}

		// Parse based on operating system
		switch os {
		case "windows":
			if strings.Contains(line, "time=") && strings.Contains(line, "ttl=") {
				// Windows format: "Reply from 192.168.1.1: bytes=32 time=12ms TTL=64"
				timeIndex := strings.Index(line, "time=")
				if timeIndex == -1 {
					continue
				}
				timeStr := line[timeIndex+5:]
				msIndex := strings.Index(timeStr, "ms")
				if msIndex == -1 {
					continue
				}
				timeStr = timeStr[:msIndex]
				if latency, err := strconv.ParseFloat(timeStr, 64); err == nil {
					latencies = append(latencies, latency)
				}
			}
		default:
			// Unix-like format: "64 bytes from 8.8.8.8: icmp_seq=0 ttl=117 time=12.345 ms"
			if strings.Contains(line, "time=") {
				parts := strings.Split(line, "time=")
				if len(parts) < 2 {
					continue
				}
				timePart := parts[1]
				spaceIndex := strings.Index(timePart, " ")
				if spaceIndex == -1 {
					continue
				}
				timeStr := timePart[:spaceIndex]
				if latency, err := strconv.ParseFloat(timeStr, 64); err == nil {
					latencies = append(latencies, latency)
				}
			}
		}
	}

	return latencies, nil
}

func main() {
	// Example usage
	host := "8.8.8.8"
	count := 4

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average latency to %s over %d pings: %.2f ms\n", host, count, avgLatency)
}

