package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host a given number of times and returns
// the average latency in milliseconds. Uses the system ping command.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be positive, got %d", count)
	}
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	// Build ping command based on OS
	var cmd *exec.Cmd
	if isWindows() {
		cmd = exec.Command("ping", host, "-n", strconv.Itoa(count))
	} else {
		// Unix-like systems (Linux, macOS)
		cmd = exec.Command("ping", host, "-c", strconv.Itoa(count))
	}

	var stdout, stderr bytes.Buffer
	cmd.Stdout = &stdout
	cmd.Stderr = &stderr

	if err := cmd.Run(); err != nil {
		return 0, fmt.Errorf("ping command failed: %v\nstderr: %s", err, stderr.String())
	}

	// Parse output based on OS
	output := stdout.String()
	var times []float64
	if isWindows() {
		times = parseWindowsPing(output)
	} else {
		times = parseUnixPing(output)
	}

	if len(times) == 0 {
		return 0, fmt.Errorf("no valid ping times found in output")
	}

	// Calculate average
	var sum float64
	for _, t := range times {
		sum += t
	}
	return sum / float64(len(times)), nil
}

// parseUnixPing extracts ping times from Linux/macOS ping output
func parseUnixPing(output string) []float64 {
	var times []float64
	// Match lines like: "64 bytes from 8.8.8.8: icmp_seq=0 ttl=115 time=12.3 ms"
	re := regexp.MustCompile(`time=([0-9.]+)\s*ms`)
	matches := re.FindAllStringSubmatch(output, -1)
	for _, match := range matches {
		if len(match) > 1 {
			if t, err := strconv.ParseFloat(match[1], 64); err == nil {
				times = append(times, t)
			}
		}
	}
	return times
}

// parseWindowsPing extracts ping times from Windows ping output
func parseWindowsPing(output string) []float64 {
	var times []float64
	// Match lines like: "Reply from 8.8.8.8: bytes=32 time=12ms TTL=115"
	re := regexp.MustCompile(`time=([0-9.]+)\s*ms`)
	matches := re.FindAllStringSubmatch(output, -1)
	for _, match := range matches {
		if len(match) > 1 {
			if t, err := strconv.ParseFloat(match[1], 64); err == nil {
				times = append(times, t)
			}
		}
	}
	return times
}

// isWindows checks if the current OS is Windows
func isWindows() bool {
	return strings.Contains(strings.ToLower(os.Getenv("OS")), "windows") ||
		strings.Contains(strings.ToLower(runtime.GOOS), "windows")
}

// Example usage in main function
