package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// statsRegex is a compiled regex to extract average latency from ping output
var statsRegex = regexp.MustCompile(`(\d+\.?\d*)/(\d+\.?\d*)/(\d+\.?\d*)/(\d+\.?\d*)`)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Use direct exec.Command without shell to avoid injection vulnerabilities
	// and improve cross-platform compatibility
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		// Check if ping failed but still produced output (partial success)
		// Some ping implementations return non-zero exit codes for packet loss
		// but still provide statistics
		if len(output) == 0 {
			return 0, fmt.Errorf("failed to execute ping: %w", err)
		}
		// Continue parsing even if there's an error, as ping might have partial results
	}

	// Look for the line containing RTT statistics
	outputStr := string(output)
	lines := strings.Split(outputStr, "\n")
	var statsLine string
	for _, line := range lines {
		// Match common ping output patterns across different systems
		if strings.Contains(line, "rtt min/avg/max") || 
		   strings.Contains(line, "round-trip min/avg/max") ||
		   strings.Contains(line, "Minimum =") && strings.Contains(line, "Maximum =") && strings.Contains(line, "Average =") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	// Extract average latency using regex
	// Handle different ping output formats:
	// Linux: rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	// macOS: round-trip min/avg/max/stddev = 12.345/23.456/34.567/5.678 ms
	// Some Windows: Minimum = 12ms, Maximum = 34ms, Average = 23ms
	matches := statsRegex.FindStringSubmatch(statsLine)
	if len(matches) < 3 {
		// Try alternative format for Windows ping
		if strings.Contains(statsLine, "Average =") {
			// Extract average from "Average = 23ms" pattern
			avgStart := strings.Index(statsLine, "Average =")
			if avgStart != -1 {
				avgPart := statsLine[avgStart+9:]
				avgPart = strings.TrimSpace(avgPart)
				// Remove "ms" suffix if present
				avgPart = strings.TrimSuffix(avgPart, "ms")
				avgPart = strings.TrimSpace(avgPart)
				avg, err := strconv.ParseFloat(avgPart, 64)
				if err == nil {
					return avg, nil
				}
			}
		}
		return 0, errors.New("failed to parse average latency from ping output")
	}

	// The second match is the average (format: min/avg/max/mdev)
	avgStr := matches[2]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

