package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
	"runtime"
	"strconv"
	"strings"
	"time"
)

// MeasureLatency pings the specified host a given number of times
// and returns the average latency in milliseconds.
// It uses the system's ping command via os/exec.
func MeasureLatency(host string, count int) (float64, error) {
	// Validate inputs
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}
	if count <= 0 {
		return 0, fmt.Errorf("count must be positive")
	}

	// Build ping command based on OS
	var cmd *exec.Cmd
	switch runtime.GOOS {
	case "windows":
		cmd = exec.Command("ping", host, "-n", strconv.Itoa(count))
	case "darwin", "linux", "freebsd", "netbsd", "openbsd":
		cmd = exec.Command("ping", host, "-c", strconv.Itoa(count))
	default:
		return 0, fmt.Errorf("unsupported operating system: %s", runtime.GOOS)
	}

	// Execute command with timeout
	var stdout, stderr bytes.Buffer
	cmd.Stdout = &stdout
	cmd.Stderr = &stderr

	done := make(chan error, 1)
	go func() {
		done <- cmd.Run()
	}()

	select {
	case err := <-done:
		if err != nil {
			return 0, fmt.Errorf("ping failed: %v\nstderr: %s", err, stderr.String())
		}
	case <-time.After(30 * time.Second):
		return 0, fmt.Errorf("ping command timed out after 30 seconds")
	}

	// Parse output based on OS
	output := stdout.String()
	var totalTime float64
	var successfulPings int

	if runtime.GOOS == "windows" {
		// Windows ping output format
		lines := strings.Split(output, "\n")
		for _, line := range lines {
			line = strings.TrimSpace(line)
			if strings.Contains(line, "time=") {
				// Example: "Reply from 8.8.8.8: bytes=32 time=11ms TTL=114"
				timeIndex := strings.Index(line, "time=")
				if timeIndex == -1 {
					continue
				}

				timePart := line[timeIndex+5:]
				endIndex := strings.IndexAny(timePart, "ms")
				if endIndex == -1 {
					continue
				}

				timeStr := timePart[:endIndex]
				if timeMs, err := strconv.ParseFloat(timeStr, 64); err == nil {
					totalTime += timeMs
					successfulPings++
				}
			}
		}
	} else {
		// Unix-like ping output format
		lines := strings.Split(output, "\n")
		for _, line := range lines {
			line = strings.TrimSpace(line)
			// Example: "64 bytes from 8.8.8.8: icmp_seq=1 ttl=114 time=11.234 ms"
			if strings.Contains(line, "time=") {
				parts := strings.Split(line, "time=")
				if len(parts) < 2 {
					continue
				}

				timePart := strings.Fields(parts[1])[0]
				if timeMs, err := strconv.ParseFloat(timePart, 64); err == nil {
					totalTime += timeMs
					successfulPings++
				}
			}
		}
	}

	if successfulPings == 0 {
		return 0, fmt.Errorf("no successful ping responses received")
	}

	return totalTime / float64(successfulPings), nil
}

func main() {
	// Example usage with command-line arguments
	if len(os.Args) < 3 {
		fmt.Println("Usage: go run main.go <host> <count>")
		fmt.Println("Example: go run main.go 8.8.8.8 4")
		os.Exit(1)
	}

	host := os.Args[1]
	count, err := strconv.Atoi(os.Args[2])
	if err != nil {
		fmt.Printf("Invalid count: %v\n", err)
		os.Exit(1)
	}

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s: %.2f ms (based on %d pings)\n", 
		host, avgLatency, count)
}

