package main

import (
    "bytes"
    "fmt"
    "os/exec"
    "runtime"
    "strconv"
    "strings"
)

// MeasureLatency pings the specified host a given number of times and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
    if count <= 0 {
        return 0, fmt.Errorf("count must be positive")
    }

    // Build ping command based on OS
    var cmd *exec.Cmd
    switch runtime.GOOS {
    case "windows":
        cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
    case "darwin", "linux", "freebsd", "netbsd", "openbsd":
        cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
    default:
        return 0, fmt.Errorf("unsupported operating system: %s", runtime.GOOS)
    }

    // Execute command and capture output
    var out bytes.Buffer
    cmd.Stdout = &out
    cmd.Stderr = &out

    if err := cmd.Run(); err != nil {
        return 0, fmt.Errorf("ping failed: %v\noutput: %s", err, out.String())
    }

    // Parse output based on OS
    var totalTime, receivedCount float64
    output := out.String()

    switch runtime.GOOS {
    case "windows":
        // Windows format: "Reply from 192.168.1.1: bytes=32 time=1ms TTL=64"
        lines := strings.Split(output, "\n")
        for _, line := range lines {
            if strings.Contains(line, "time=") && strings.Contains(line, "Reply from") {
                parts := strings.Split(line, "time=")
                if len(parts) < 2 {
                    continue
                }
                timePart := strings.Split(parts[1], "ms")[0]
                time, err := strconv.ParseFloat(timePart, 64)
                if err == nil {
                    totalTime += time
                    receivedCount++
                }
            }
        }
    default:
        // Unix-like format: "64 bytes from 8.8.8.8: icmp_seq=0 ttl=117 time=11.9 ms"
        lines := strings.Split(output, "\n")
        for _, line := range lines {
            if strings.Contains(line, "time=") {
                parts := strings.Split(line, "time=")
                if len(parts) < 2 {
                    continue
                }
                timePart := strings.Split(parts[1], " ")[0]
                time, err := strconv.ParseFloat(timePart, 64)
                if err == nil {
                    totalTime += time
                    receivedCount++
                }
            }
        }
    }

    if receivedCount == 0 {
        return 0, fmt.Errorf("no valid ping responses received")
    }

    return totalTime / receivedCount, nil
}

func main() {
    // Example usage
    host := "8.8.8.8"
    count := 4

    avgLatency, err := MeasureLatency(host, count)
    if err != nil {
        fmt.Printf("Error: %v\n", err)
        return
    }

    fmt.Printf("Average latency to %s: %.2f ms\n", host, avgLatency)
}

