import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings a specified host a given number of times and returns the average latency in milliseconds.
// It uses the system's ping command via os/exec package.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be positive, got %d", count)
	}
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	// Determine ping command based on OS
	var cmd *exec.Cmd
	switch runtime.GOOS {
	case "windows":
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	case "darwin", "linux", "freebsd", "netbsd", "openbsd":
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	default:
		return 0, fmt.Errorf("unsupported operating system: %s", runtime.GOOS)
	}

	var stdout, stderr bytes.Buffer
	cmd.Stdout = &stdout
	cmd.Stderr = &stderr

	if err := cmd.Run(); err != nil {
		return 0, fmt.Errorf("ping command failed: %v\nstderr: %s", err, stderr.String())
	}

	// Parse output to extract latency values
	output := stdout.String()
	var totalLatency float64
	var validPings int

	lines := strings.Split(output, "\n")
	for _, line := range lines {
		line = strings.ToLower(line)

		// Different parsing for Windows vs Unix-like systems
		if runtime.GOOS == "windows" {
			// Windows format: "Reply from 192.168.1.1: bytes=32 time=1ms TTL=64"
			if strings.Contains(line, "time=") && strings.Contains(line, "ttl=") {
				timeIndex := strings.Index(line, "time=")
				if timeIndex != -1 {
					timePart := line[timeIndex+5:]
					msIndex := strings.Index(timePart, "ms")
					if msIndex != -1 {
						timeStr := strings.TrimSpace(timePart[:msIndex])
						if timeFloat, err := strconv.ParseFloat(timeStr, 64); err == nil {
							totalLatency += timeFloat
							validPings++
						}
					}
				}
			}
		} else {
			// Unix-like format: "64 bytes from 8.8.8.8: icmp_seq=0 ttl=117 time=11.4 ms"
			if strings.Contains(line, "time=") {
				timeIndex := strings.Index(line, "time=")
				if timeIndex != -1 {
					timePart := line[timeIndex+5:]
					msIndex := strings.Index(timePart, "ms")
					if msIndex != -1 {
						timeStr := strings.TrimSpace(timePart[:msIndex])
						if timeFloat, err := strconv.ParseFloat(timeStr, 64); err == nil {
							totalLatency += timeFloat
							validPings++
						}
					}
				}
			}
		}
	}

	if validPings == 0 {
		return 0, fmt.Errorf("no valid ping responses received")
	}

	return totalLatency / float64(validPings), nil
}

func main() {
	// Example usage
	host := "8.8.8.8" // Google DNS
	count := 4

	latency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s over %d pings: %.2f ms\n", host, count, latency)
}

