)

// MeasureLatency pings a specified host a given number of times and returns
// the average latency in milliseconds. It uses the system's ping command
// via os/exec. Supports Linux, macOS, and Windows ping command formats.
func MeasureLatency(host string, count int) (float64, error) {
	// Validate input parameters
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Determine ping command based on operating system
	var cmd *exec.Cmd
	osType := getOS()
	switch osType {
	case "windows":
		cmd = exec.Command("ping", host, "-n", strconv.Itoa(count))
	case "darwin", "linux":
		cmd = exec.Command("ping", host, "-c", strconv.Itoa(count))
	default:
		return 0, fmt.Errorf("unsupported operating system: %s", osType)
	}

	// Execute ping command and capture output
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %v", err)
	}

	// Parse average latency from ping output
	avgLatency, err := parsePingOutput(string(output), osType)
	if err != nil {
		return 0, fmt.Errorf("failed to parse ping output: %v", err)
	}

	return avgLatency, nil
}

// getOS returns the current operating system identifier
func getOS() string {
	// Use runtime.GOOS instead of environment variable for reliability
	return strings.ToLower(runtime.GOOS)
}

// parsePingOutput extracts average latency from ping command output
// based on the operating system's ping output format
func parsePingOutput(output, os string) (float64, error) {
	var pattern string
	var matchIndex int

	switch os {
	case "windows":
		// Windows ping output: "Average = 15ms"
		pattern = `Average = (\d+)ms`
		matchIndex = 1
	case "darwin", "linux":
		// macOS/Linux ping output: "min/avg/max/mdev = 1.234/5.678/9.012/3.456 ms"
		pattern = `(\d+\.?\d*)/(\d+\.?\d*)/(\d+\.?\d*)/(\d+\.?\d*)\s*ms`
		matchIndex = 2 // Second value is average
	default:
		return 0, fmt.Errorf("unsupported OS for parsing: %s", os)
	}

	re := regexp.MustCompile(pattern)
	matches := re.FindStringSubmatch(output)
	if matches == nil || len(matches) <= matchIndex {
		return 0, errors.New("could not find latency pattern in ping output")
	}

	// Convert matched string to float64
	latency, err := strconv.ParseFloat(matches[matchIndex], 64)
	if err != nil {
		return 0, fmt.Errorf("failed to parse latency value: %v", err)
	}

	return latency, nil
}

func main() {
