package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Build ping command based on operating system
	var cmd *exec.Cmd
	switch runtime.GOOS {
	case "windows":
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	case "darwin":
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	default: // Linux and other Unix-like systems
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		// Check if ping failed but still produced output (e.g., unknown host)
		if len(output) == 0 {
			return 0, fmt.Errorf("failed to execute ping: %w", err)
		}
		// Continue parsing even if ping returns error (e.g., packet loss)
	}

	// Look for the line containing RTT statistics
	outputStr := string(output)
	lines := strings.Split(outputStr, "\n")
	var statsLine string
	for _, line := range lines {
		// Match different ping output formats across OSes
		if strings.Contains(line, "min/avg/max") || 
		   strings.Contains(line, "Minimum =") || 
		   strings.Contains(line, "avg =") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	// Extract average latency using OS-specific regex patterns
	var avgStr string
	switch runtime.GOOS {
	case "windows":
		// Windows format: Minimum = 10ms, Maximum = 20ms, Average = 15ms
		re := regexp.MustCompile(`Average = (\d+)ms`)
		matches := re.FindStringSubmatch(statsLine)
		if len(matches) < 2 {
			return 0, errors.New("failed to parse average latency from Windows ping output")
		}
		avgStr = matches[1]
	default:
		// Unix/Linux/macOS format: rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
		re := regexp.MustCompile(`(\d+\.?\d*)/(\d+\.?\d*)/(\d+\.?\d*)/(\d+\.?\d*)`)
		matches := re.FindStringSubmatch(statsLine)
		if len(matches) < 3 {
			return 0, errors.New("failed to parse average latency from ping output")
		}
		avgStr = matches[2] // Second group is average
	}

	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

