// MeasureLatency pings the specified host a given number of times
// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	// Validate input parameters
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}
	if count <= 0 {
		return 0, fmt.Errorf("count must be greater than 0")
	}

	// Construct the ping command based on operating system
	var cmd *exec.Cmd
	if isWindows() {
		// Windows ping uses -n for count and -w for timeout (milliseconds)
		cmd = exec.Command("ping", host, "-n", strconv.Itoa(count), "-w", "1000")
	} else {
		// Unix-like systems (Linux, macOS) use -c for count
		cmd = exec.Command("ping", host, "-c", strconv.Itoa(count))
	}

	// Execute the command and capture output
	output, err := cmd.CombinedOutput()
	if err != nil {
		// Check if the error is due to ping command failure (not exit status 0)
		if exitErr, ok := err.(*exec.ExitError); ok {
			// Ping sometimes returns non-zero exit code even with partial results
			// We'll try to parse the output anyway
			if len(output) == 0 {
				return 0, fmt.Errorf("ping failed with exit code %d: %v", exitErr.ExitCode(), err)
			}
		} else {
			return 0, fmt.Errorf("failed to execute ping command: %v", err)
		}
	}

	// Parse the ping output to extract latency values
	latencies, err := parsePingOutput(string(output))
	if err != nil {
		return 0, fmt.Errorf("failed to parse ping output: %v", err)
	}

	if len(latencies) == 0 {
		return 0, fmt.Errorf("no latency data found in ping output")
	}

	// Calculate average latency
	var sum float64
	for _, latency := range latencies {
		sum += latency
	}
	return sum / float64(len(latencies)), nil
}

// parsePingOutput extracts latency values from ping command output
func parsePingOutput(output string) ([]float64, error) {
	var latencies []float64
	scanner := bufio.NewScanner(strings.NewReader(output))

	// Different regex patterns for different ping output formats
	patterns := []*regexp.Regexp{
		// Windows format: "Reply from 192.168.1.1: bytes=32 time=1ms TTL=64"
		regexp.MustCompile(`time[=<>](\d+(?:\.\d+)?)\s*ms`),
		// Linux/macOS format: "64 bytes from 8.8.8.8: icmp_seq=0 ttl=117 time=12.3 ms"
		regexp.MustCompile(`time[=<>](\d+(?:\.\d+)?)\s*ms`),
		// Alternative format with equals sign: "time=10.5 ms"
		regexp.MustCompile(`time=(\d+(?:\.\d+)?)\s*ms`),
	}

	for scanner.Scan() {
		line := scanner.Text()
		for _, pattern := range patterns {
			matches := pattern.FindStringSubmatch(line)
			if matches != nil && len(matches) > 1 {
				latency, err := strconv.ParseFloat(matches[1], 64)
				if err == nil {
					latencies = append(latencies, latency)
					break // Move to next line after finding a match
				}
			}
		}
	}

	if err := scanner.Err(); err != nil {
		return nil, err
	}

	return latencies, nil
}

// isWindows checks if the current operating system is Windows
func isWindows() bool {
	// This is a simplified check - in production you'd use runtime.GOOS
	cmd := exec.Command("cmd", "/c", "ver")
	err := cmd.Run()
	return err == nil
}

func main() {
	// Example usage
	host := "8.8.8.8" // Google DNS
	count := 4

	fmt.Printf("Measuring latency to %s with %d pings...\n", host, count)

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	fmt.Printf("Average latency: %.2f ms\n", avgLatency)
}

