// MeasureLatency pings the specified host a given number of times
// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	// Validate inputs
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}
	if count <= 0 {
		return 0, fmt.Errorf("count must be positive")
	}

	// Build ping command based on OS
	var cmd *exec.Cmd
	switch runtime.GOOS {
	case "windows":
		cmd = exec.Command("ping", host, "-n", strconv.Itoa(count))
	case "darwin", "linux", "freebsd", "netbsd", "openbsd":
		cmd = exec.Command("ping", host, "-c", strconv.Itoa(count))
	default:
		return 0, fmt.Errorf("unsupported operating system: %s", runtime.GOOS)
	}

	// Execute command with timeout
	var stdout, stderr bytes.Buffer
	cmd.Stdout = &stdout
	cmd.Stderr = &stderr

	done := make(chan error, 1)
	go func() {
		done <- cmd.Run()
	}()

	select {
	case err := <-done:
		if err != nil {
			return 0, fmt.Errorf("ping failed: %v, stderr: %s", err, stderr.String())
		}
	case <-time.After(30 * time.Second):
		return 0, fmt.Errorf("ping timed out after 30 seconds")
	}

	// Parse output based on OS
	output := stdout.String()
	var totalLatency float64
	var successfulPings int

	switch runtime.GOOS {
	case "windows":
		// Windows format: "Reply from 192.168.1.1: bytes=32 time=1ms TTL=64"
		lines := strings.Split(output, "\n")
		for _, line := range lines {
			if strings.Contains(line, "time=") {
				// Extract time value
				timeIndex := strings.Index(line, "time=")
				if timeIndex == -1 {
					continue
				}

				timeStr := line[timeIndex+5:]
				endIndex := strings.IndexAny(timeStr, "ms ")
				if endIndex == -1 {
					continue
				}

				timeStr = timeStr[:endIndex]
				latency, err := strconv.ParseFloat(timeStr, 64)
				if err == nil {
					totalLatency += latency
					successfulPings++
				}
			}
		}
	default:
		// Unix format: "64 bytes from 8.8.8.8: icmp_seq=1 ttl=117 time=12.3 ms"
		lines := strings.Split(output, "\n")
		for _, line := range lines {
			if strings.Contains(line, "time=") {
				// Extract time value
				parts := strings.Split(line, "time=")
				if len(parts) < 2 {
					continue
				}

				timePart := parts[1]
				endIndex := strings.Index(timePart, " ms")
				if endIndex == -1 {
					continue
				}

				timeStr := timePart[:endIndex]
				latency, err := strconv.ParseFloat(timeStr, 64)
				if err == nil {
					totalLatency += latency
					successfulPings++
				}
			}
		}
	}

	// Calculate average
	if successfulPings == 0 {
		return 0, fmt.Errorf("no successful pings received")
	}

	return totalLatency / float64(successfulPings), nil
}

func main() {
	// Example usage
	host := "8.8.8.8" // Google DNS
	count := 4

	fmt.Printf("Measuring latency to %s with %d pings...\n", host, count)

	latency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	fmt.Printf("Average latency: %.2f ms\n", latency)
}

